defmodule DevopsAutomation.CommandService do
  @moduledoc """
  A safe command execution service that only allows pre-approved commands.
  Never pass raw user input to a shell.
  """

  # Allowlist of permitted commands with their expected argument patterns
  @allowed_commands %{
    "disk_usage" => {"/usr/bin/df", ["-h"]},
    "memory_info" => {"/usr/bin/free", ["-m"]},
    "uptime" => {"/usr/bin/uptime", []},
    "list_containers" => {"/usr/bin/docker", ["ps", "--format", "table {{.Names}}\t{{.Status}}"]},
    "service_status" => {"/usr/bin/systemctl", ["status"]},
    "ping" => {"/usr/bin/ping", ["-c", "4"]}
  }

  @doc """
  Executes a pre-approved command by name with optional validated arguments.
  Returns {:ok, output} or {:error, reason}.
  """
  def execute(command_name, user_args \\ []) when is_binary(command_name) and is_list(user_args) do
    with {:ok, {executable, base_args}} <- lookup_command(command_name),
         {:ok, sanitized_args} <- validate_args(command_name, user_args) do
      full_args = base_args ++ sanitized_args

      try do
        {output, exit_code} =
          System.cmd(executable, full_args,
            stderr_to_stdout: true,
            env: clean_env(),
            timeout: 30_000
          )

        case exit_code do
          0 -> {:ok, %{output: output, exit_code: 0}}
          code -> {:error, %{output: output, exit_code: code}}
        end
      rescue
        e in ErlangError ->
          {:error, %{reason: "Command execution failed: #{inspect(e)}"}}
      end
    end
  end

  defp lookup_command(command_name) do
    case Map.get(@allowed_commands, command_name) do
      nil -> {:error, %{reason: "Command '#{command_name}' is not in the allowlist"}}
      cmd_tuple -> {:ok, cmd_tuple}
    end
  end

  # Validate and sanitize arguments per command
  defp validate_args("service_status", [service_name]) do
    if valid_service_name?(service_name) do
      {:ok, [service_name]}
    else
      {:error, %{reason: "Invalid service name: #{service_name}"}}
    end
  end

  defp validate_args("service_status", _),
    do: {:error, %{reason: "service_status requires exactly one argument: the service name"}}

  defp validate_args("ping", [hostname]) do
    if valid_hostname?(hostname) do
      {:ok, [hostname]}
    else
      {:error, %{reason: "Invalid hostname: #{hostname}"}}
    end
  end

  defp validate_args("ping", _),
    do: {:error, %{reason: "ping requires exactly one argument: the hostname"}}

  # Commands that take no user-supplied arguments
  defp validate_args(_command_name, []), do: {:ok, []}

  defp validate_args(_command_name, _args),
    do: {:error, %{reason: "This command does not accept additional arguments"}}

  defp valid_service_name?(name) when is_binary(name) do
    Regex.match?(~r/\A[a-zA-Z0-9_\-\.]+\z/, name) and String.length(name) <= 128
  end

  defp valid_service_name?(_), do: false

  defp valid_hostname?(hostname) when is_binary(hostname) do
    Regex.match?(~r/\A[a-zA-Z0-9\-\.]+\z/, hostname) and String.length(hostname) <= 253
  end

  defp valid_hostname?(_), do: false

  defp clean_env do
    [
      {"PATH", "/usr/local/bin:/usr/bin:/bin"},
      {"LC_ALL", "C"}
    ]
  end

  def list_available_commands do
    Map.keys(@allowed_commands)
  end
end

defmodule DevopsAutomationWeb.CommandController do
  use DevopsAutomationWeb, :controller

  alias DevopsAutomation.CommandService

  @doc """
  POST /api/commands/execute
  Body: {"command": "disk_usage", "args": []}
  """
  def execute(conn, %{"command" => command_name} = params) do
    args = Map.get(params, "args", [])

    unless is_list(args) and Enum.all?(args, &is_binary/1) do
      conn
      |> put_status(:bad_request)
      |> json(%{error: "args must be a list of strings"})
      |> halt()
    else
      case CommandService.execute(command_name, args) do
        {:ok, result} ->
          json(conn, %{status: "success", data: result})

        {:error, %{reason: reason}} ->
          conn
          |> put_status(:unprocessable_entity)
          |> json(%{status: "error", error: reason})

        {:error, %{output: output, exit_code: code}} ->
          conn
          |> put_status(:unprocessable_entity)
          |> json(%{status: "error", exit_code: code, output: output})
      end
    end
  end

  def execute(conn, _params) do
    conn
    |> put_status(:bad_request)
    |> json(%{error: "Missing required parameter: command"})
  end

  def index(conn, _params) do
    json(conn, %{available_commands: CommandService.list_available_commands()})
  end
end